    .ready_i ( sbr_port_req_i.b_ready ),
    .data_o  ( sbr_port_rsp_o.b       )
  );

  spill_register #(
    .T       ( ar_chan_t ),
    .Bypass  ( Bypass    )
  ) i_reg_ar (
    .clk_i   ( clk_i              ),
