    .valid_i ( sbr_port_req_i.ar_valid ),
    .ready_o ( sbr_port_rsp_o.ar_ready ),
    .data_i  ( sbr_port_req_i.ar       ),
    .valid_o ( mgr_port_req_o.ar_valid ),
    .ready_i ( mgr_port_rsp_i.ar_ready ),
    .data_o  ( mgr_port_req_o.ar       )
  );

  spill_register #(
    .T       ( r_chan_t ),
