        "type" : "\"R\"",
        "time" : $sformatf("%d", $time()),
        "id"   : $sformatf("0x%0x", axi_rsp_i.r.id),
        "data" : $sformatf("0x%0x", axi_rsp_i.r.data),
        "resp" : $sformatf("0x%0x", axi_rsp_i.r.resp),
        "last" : $sformatf("0x%0x", axi_rsp_i.r.last),
