    r_busy_d    = r_busy_q;
    r_busy_load = 1'b0;
    // r fifo signals
    r_fifo_pop  = 1'b0;
    // r counter signals
    r_cnt_clear = 1'b0;
    r_cnt_en    = 1'b0;
    r_cnt_load  = 1'b0;
    // r_channel
    err_rsp.r        = '0;
    err_rsp.r.id     = r_fifo_data.id;
    err_rsp.r.data   = RespData;
    err_rsp.r.resp   = Resp;
    err_rsp.r_valid  = 1'b0;
    // control
    if (r_busy_q) begin
      err_rsp.r_valid = 1'b1;
      err_rsp.r.last = (r_current_beat == '0);
