  `AXI_ASSIGN_R_STRUCT  ( sbr_port_rsp_o.r        , mgr_read_rsp_i.r  )

  // Read AW and W channel data
  assign mgr_read_req_o.aw        = '0;
  assign mgr_read_req_o.w         = '0;


