);
  // full bus declarations
  axi_req_t filtered_req, splitted_req;
  axi_rsp_t filtered_rsp, splitted_rsp;

  // atomics adapter so that atomics can be resolved
  axi_atop_filter #(
    .IdWidth      ( IdWidth      ),
